import { PartialType } from '@nestjs/mapped-types';
import { CreateUserDto } from './create-user.dto';
import { IsOptional, IsString, MinLength } from 'class-validator';

// Première méthode : utiliser PartialType directement
export class UpdateUserDto extends PartialType(CreateUserDto) {}

// Deuxième méthode : avec validation supplémentaire spécifique à la mise à jour
export class UpdateUserDto extends PartialType(CreateUserDto) {
  @IsOptional()
  @IsString()
  @MinLength(8, { message: 'Le nouveau mot de passe doit faire au moins 8 caractères' })
  password?: string;
}
```

Explication : PartialType rend toutes les propriétés du DTO parent optionnelles. Cela est parfait pour PATCH (mise à jour partielle). Il conserve également tous les décorateurs de validation du parent, qui ne seront appliqués que si la propriété est présente dans la requête.

