// is-phone-number.validator.ts
import {
  registerDecorator,
  ValidationOptions,
  ValidatorConstraint,
  ValidatorConstraintInterface,
} from 'class-validator';

@ValidatorConstraint({ async: false })
export class IsPhoneNumberConstraint implements ValidatorConstraintInterface {
  validate(phoneNumber: string): boolean {
    if (!phoneNumber) return false;

    // Format local : 6 chiffres
    const localRegex = /^[267]\d{5}$/;
    // Format international : +237 + 9 chiffres
    const internationalRegex = /^\+237[267]\d{8}$/;

    return localRegex.test(phoneNumber) || internationalRegex.test(phoneNumber);
  }

  defaultMessage(): string {
    return 'Le numéro de téléphone doit être valide (ex: 612345678 ou +237612345678)';
  }
}

export function IsPhoneNumber(validationOptions?: ValidationOptions) {
  return function (object: object, propertyName: string) {
    registerDecorator({
      target: object.constructor,
      propertyName: propertyName,
      options: validationOptions,
      constraints: [],
      validator: IsPhoneNumberConstraint,
    });
  };
}

