// main.ts
import { NestFactory } from '@nestjs/core';
import { ValidationPipe } from '@nestjs/common';
import { AppModule } from './app.module';

async function bootstrap() {
  const app = await NestFactory.create(AppModule);

  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,               // Supprime les propriétés non déclarées dans le DTO
      forbidNonWhitelisted: true,    // Lance une erreur si des propriétés non déclarées sont présentes
      transform: true,               // Transforme automatiquement les payloads en instances de DTO
      disableErrorMessages: false,   // Affiche les messages d'erreur détaillés (à désactiver en prod)
    }),
  );

  await app.listen(3000);
}
bootstrap();
```

Explication des options :
- **whitelist** : Nettoie automatiquement l'objet reçu en supprimant toutes les propriétés qui n'ont pas de décorateur dans le DTO. Sécurité et propreté.
- **forbidNonWhitelisted** : Si une propriété non déclarée est présente, NestJS lève une erreur BadRequest. Complémentaire à whitelist.
- **transform** : Convertit automatiquement les valeurs vers les types définis dans le DTO (ex: string '18' → number 18 pour @IsInt()).
- **disableErrorMessages** : En production, mettez à true pour éviter d'exposer des détails d'implémentation.

