import { Type } from 'class-transformer';
import { 
  IsArray, 
  ValidateNested, 
  IsNumber, 
  Min, 
  Max, 
  IsString, 
  IsNotEmpty,
  IsIn,
  ArrayMinSize,
  IsInt,
  IsOptional
} from 'class-validator';

class OrderItemDto {
  @IsInt()
  @Min(1)
  productId: number;

  @IsInt()
  @Min(1)
  @Max(99)
  quantity: number;

  @IsOptional()
  @IsString()
  notes?: string;
}

class AddressDto {
  @IsString()
  @IsNotEmpty()
  street: string;

  @IsString()
  @IsNotEmpty()
  city: string;

  @IsString()
  @IsNotEmpty()
  zipCode: string;

  @IsString()
  @IsNotEmpty()
  country: string;
}

export class CreateOrderDto {
  @IsArray()
  @ArrayMinSize(1)
  @ValidateNested({ each: true })
  @Type(() => OrderItemDto)
  items: OrderItemDto[];

  @ValidateNested()
  @Type(() => AddressDto)
  shippingAddress: AddressDto;

  @IsIn(['card', 'paypal'])
  paymentMethod: 'card' | 'paypal';

  @IsOptional()
  @IsString()
  notes?: string;
}
